181→    // Look for the tool registration export
182→    // We'll check for different possible export patterns
183→    let registration: ToolRegistration | null = null;
184→    
185→    // Pattern 1: Direct export of ToolRegistration
186→    if (module.default && typeof module.default === 'object' && 
187→        module.default.tool && module.default.handler) {
188→      registration = module.default;
189→    }
190→    
191→    // Pattern 2: Named export 'registration'
192→    if (!registration && module.registration && typeof module.registration === 'object' &&
193→        module.registration.tool && module.registration.handler) {
194→      registration = module.registration;
195→    }
196→    
197→    // Pattern 3: Separate tool and handler exports (legacy pattern)
198→    if (!registration) {
199→      // Try to find tool and handler exports
200→      const toolExport = Object.values(module).find(exp => 
201→        typeof exp === 'object' && exp !== null && 
202→        'name' in exp && 'description' in exp && 'inputSchema' in exp
203→      );
204→      
205→      const handlerExport = Object.values(module).find(exp => 
206→        typeof exp === 'function' && exp.name.includes('handle')
207→      );
