209→      if (toolExport && handlerExport) {
210→        registration = {
211→          tool: toolExport as any,
212→          handler: handlerExport as any,
213→          schema: (toolExport as any).inputSchema
214→        };
215→      }
216→    }
217→    
218→    if (!registration) {
219→      logger.warn(`No valid tool registration found in ${filePath}`);
220→      return null;
221→    }
222→    
223→    // Validate the registration
224→    if (!registration.tool || !registration.tool.name || !registration.handler) {
225→      logger.warn(`Invalid tool registration in ${filePath}: missing tool name or handler`);
226→      return null;
227→    }
228→    
229→    return registration;
230→    
