239→ * 
240→ * @param options - Scanning options
241→ * @returns Tool registry with all loaded tools
242→ */
243→export async function loadTools(options: Partial<ToolScanOptions> = {}): Promise<ToolRegistry> {
244→  const opts = { ...DEFAULT_SCAN_OPTIONS, ...options };
245→  
246→  logger.info(`Scanning for CLI tools in ${opts.baseDir} with pattern ${opts.pattern}`);
247→  
248→  const registry: ToolRegistry = {
249→    tools: new Map(),
250→    handlers: new Map(),
251→    schemas: new Map()
252→  };
253→  
254→  try {
255→    // Scan for tool files
256→    const toolFiles = await scanDirectory(opts.baseDir, opts.pattern);
257→    
258→    logger.info(`Found ${toolFiles.length} potential tool files`);
259→    
260→    // Load each tool file
261→    for (const filePath of toolFiles) {
262→      const registration = await loadToolFromFile(filePath);
263→      
264→      if (registration) {
265→        const toolName = registration.tool.name;
266→        
267→        // Check if tool is excluded
268→        if (EXCLUDED_TOOLS.has(toolName)) {
269→          logger.info(
270→            `Tool '${toolName}' is excluded from registry: ${EXCLUDED_TOOLS_WITH_REASONS[toolName] ?? 'disabled'}`
271→          );
272→          continue;
273→        }
274→        
275→        // Check for duplicate tool names
276→        if (registry.tools.has(toolName)) {
277→          logger.warn(`Duplicate tool name '${toolName}' found in ${filePath}, skipping`);
278→          continue;
279→        }
280→        
281→        // Register the tool
282→        registry.tools.set(toolName, registration.tool);
283→        registry.handlers.set(toolName, registration.handler);
284→        
285→        if (registration.schema) {
286→          registry.schemas.set(toolName, registration.schema);
287→        }
288→        
289→        logger.debug(`Loaded tool '${toolName}' from ${filePath}`);
290→      }
291→    }
292→    
293→    logger.info(`Successfully loaded ${registry.tools.size} CLI tools`);
294→    
295→  } catch (error) {
296→    logger.error('Failed to load CLI tools:', error);
297→  }
298→  
299→  return registry;
300→}
