302→/**
303→ * Scans for tools and returns a summary result
304→ * 
305→ * @param options - Scanning options
306→ * @returns Scan result with statistics
307→ */
308→export async function scanTools(options: Partial<ToolScanOptions> = {}): Promise<ToolScanResult> {
309→  const opts = { ...DEFAULT_SCAN_OPTIONS, ...options };
310→  
311→  const result: ToolScanResult = {
312→    loaded: 0,
313→    failed: 0,
314→    failures: [],
315→    toolNames: []
316→  };
317→  
318→  try {
319→    // Scan for tool files
320→    const toolFiles = await scanDirectory(opts.baseDir, opts.pattern);
321→    
322→    // Load each tool file
323→    for (const filePath of toolFiles) {
324→      const registration = await loadToolFromFile(filePath);
325→      
326→      if (registration) {
327→        const toolName = registration.tool.name;
328→        
329→        // Check if tool is excluded
330→        if (EXCLUDED_TOOLS.has(toolName)) {
331→          // Don't count excluded tools as failed, but don't add them to results
332→          continue;
333→        }
334→        
335→        result.loaded++;
336→        result.toolNames.push(toolName);
337→      } else {
338→        result.failed++;
339→        result.failures.push({
340→          file: filePath,
341→          error: 'Failed to load tool registration'
342→        });
343→      }
344→    }
345→    
346→  } catch (error) {
347→    result.failed++;
348→    result.failures.push({
349→      file: opts.baseDir,
350→      error: error instanceof Error ? error.message : String(error)
351→    });
352→  }
353→  
354→  return result;
355→}
356→
357→/**
358→ * Gets the tool registry instance
359→ * 
360→ * @remarks
361→ * This function provides access to the global tool registry.
362→ * The registry is loaded on first access and cached for subsequent calls.
363→ */
364→let globalRegistry: ToolRegistry | null = null;
365→
366→export async function getToolRegistry(): Promise<ToolRegistry> {
367→  if (!globalRegistry) {
368→    // Load tools from the constants directory
369→    // Determine if running from build or src by checking this file's actual location
370→    const currentFileUrl = new URL(import.meta.url);
371→    const currentFilePath = currentFileUrl.pathname;
372→    const isBuilt = currentFilePath.includes('/build/') || currentFilePath.includes('/app/');
373→
374→    const baseDir = isBuilt
375→      ? resolve(process.cwd(), 'build', 'constants', 'tool', 'mittwald-cli')
376→      : resolve(process.cwd(), 'src', 'constants', 'tool', 'mittwald-cli');
377→
378→    logger.debug(`Tool registry: isBuilt=${isBuilt}, baseDir=${baseDir}`);
379→
380→    globalRegistry = await loadTools({ baseDir });
381→  }
382→
383→  return globalRegistry;
384→}
385→
386→/**
387→ * Resets the global tool registry
388→ * 
389→ * @remarks
390→ * This function is primarily used for testing purposes to reset the registry state.
391→ */
392→export function resetToolRegistry(): void {
393→  globalRegistry = null;
394→}
